// Hoje o provedor por baixo ainda ûˋ OpenAI, mas o resto do cû°digo
// deve conversar com a MIA por meio deste adapter.

function normalizeMiaLLMResponse(rawResponse = null, {
  provider = MIA_LLM_PROVIDER,
  model = MIA_TEXT_MODEL
} = {}) {
  const text =
    typeof rawResponse?.text === "string"
      ? rawResponse.text.trim()
      : getOpenAIText(rawResponse);

  return {
    text: text || "",
    usage: rawResponse?.usage || null,
    finishReason:
      rawResponse?.finishReason ||
      rawResponse?.finish_reason ||
      rawResponse?.choices?.[0]?.finish_reason ||
      "",
    provider,
    model,
    raw: rawResponse || null
  };
}

async function callMiaOpenAIProvider(messages = [], options = {}) {
  const model = options.model || MIA_TEXT_MODEL;

  const rawResponse = await callOpenAI(messages, {
    ...options,
    model
  });

  return normalizeMiaLLMResponse(rawResponse, {
    provider: "openai",
    model
  });
}

async function callMiaLLMProvider(messages = [], options = {}) {
  const provider = options.provider || MIA_LLM_PROVIDER;

  if (provider === "openai") {
    return callMiaOpenAIProvider(messages, options);
  }

  console.warn("ã ÿ¡ MIA_LLM_PROVIDER nûÈo implementado, usando fallback OpenAI:", provider);

  return callMiaOpenAIProvider(messages, {
    ...options,
    provider: "openai"
  });
}

async function callMiaLLM(messages = [], options = {}) {
  return callMiaLLMProvider(messages, {
    ...options,
    provider: options.provider || MIA_LLM_PROVIDER,
    model: options.model || MIA_TEXT_MODEL
  });
}

function getMiaLLMText(response = null) {
  if (!response) return "";

  if (typeof response.text === "string") {
    return response.text.trim();
  }

  return getOpenAIText(response);
}

function getMiaLLMUsage(response = null) {
  if (!response) return null;

  return response.usage || response.raw?.usage || null;
}

function getMiaLLMFinishReason(response = null) {
  if (!response) return "";

  return (
    response.finishReason ||
    response.finish_reason ||
    response.raw?.finishReason ||
    response.raw?.finish_reason ||
    response.raw?.choices?.[0]?.finish_reason ||
    ""
  );
}
