function getOrderedCommercialProviders(query = "") {
  const providers = [
    {
      name: "mercadolivre",
      fn: fetchFromMercadoLivreProvider,
      priority: COMMERCIAL_PROVIDERS_CONFIG.mercadolivre.priority
    },
    {
      name: "supabasecache",
      fn: fetchFromSupabaseCacheProvider,
      priority: COMMERCIAL_PROVIDERS_CONFIG.supabasecache.priority
    },
    {
      name: "serpapi",
      fn: fetchFromSerpApiProvider,
      priority: COMMERCIAL_PROVIDERS_CONFIG.serpapi.priority
    }
  ];
  return providers
    .filter((provider) => !isProviderInCooldown(provider.name))
    .sort((a, b) => a.priority - b.priority);
}
