function rankLocalFallbackProducts(products = [], query = "", options = {}) {
  if (!Array.isArray(products) || products.length === 0) return [];

  const q = normalizeQuery(query || "");
  const category = detectProductCategory(query) || "";
  const querySignals = options.querySignals || detectMiaUsageContextSignals(query);
  const gamingShield = isGamingProtectedContext(querySignals, query);
  const batteryShield = isBatteryProtectedContext(querySignals, query);
  const rankingProfile = gamingShield
    ? "gaming_performance"
    : batteryShield
      ? "battery_autonomy"
      : "";
  const priority = gamingShield
    ? "performance"
    : batteryShield
      ? "battery"
      : (detectUserPriority(query) || "");

  return products
    .map((product, index) => {
      const title = normalizeQuery(product.product_name || "");

      const scoreEngine =
        product.scoreEngine ||
        buildScoreEngineFromSpecs(product.trustedSpecs || null);

      let score = calculateTrustedSpecsRankingScore({
        product: {
          ...product,
          scoreEngine
        },
        query,
        priority,
        index,
        rankingProfile
      });

      if (category && productMatchesCategory(product, category)) {
        score += 50;
      }

      if (q && title.includes(q)) {
        score += 45;
      }

      const familyKey = getProductFamilyKey(product.product_name || "");

      if (familyKey && q.includes(familyKey)) {
        score += 60;
      }

      if (!scoreEngine?.hasTrustedScores) {
        if (priority === "battery" && /5000|6000|7000|mah|bateria/i.test(product.product_name || "")) {
          score += 25;
        }

        if (priority === "performance" && /snapdragon|dimensity|helio|ryzen|intel|i5|i7|rtx|gtx|ssd|8gb|16gb/i.test(product.product_name || "")) {
          score += 25;
        }

        if (priority === "camera" && /camera|cûÂmera|50mp|64mp|108mp|iphone|pro|ultra/i.test(product.product_name || "")) {
          score += 25;
        }

        if (priority === "storage" && /128gb|256gb|512gb|1tb/i.test(product.product_name || "")) {
          score += 25;
        }
      }

      return {
        ...product,
        scoreEngine,
        localFallbackScore: score,
        gamingShieldApplied: gamingShield,
        batteryShieldApplied: batteryShield,
        rankingProfile: rankingProfile || undefined,
        rankingBreakdown: buildRankingScoreBreakdown({
          product: { ...product, scoreEngine },
          query,
          priority,
          rankingProfile
        }),
        trustedPriorityValue: getTrustedSpecsPriorityValue(
          {
            ...product,
            scoreEngine
          },
          priority
        )
      };
    })
    .sort((a, b) => b.localFallbackScore - a.localFallbackScore);
}
function getLocalCommercialFallbackProducts({
  query = "",
  sessionContext = {},
  rememberedProducts = [],
  limit = 12
} = {}) {
  const fromCache = getRecentCommercialProductsFromCache(query, limit);

  const fromSession = Array.isArray(sessionContext?.lastProducts)
    ? sessionContext.lastProducts
    : [];

  const fromRemembered = Array.isArray(rememberedProducts)
    ? rememberedProducts
    : [];

  const merged = [
    ...fromCache,
    ...fromSession,
    ...fromRemembered
  ]
    .filter(isUsableLocalCommercialProduct)
    .filter((product) => {
      const category = detectProductCategory(query);
      return category ? productMatchesCategory(product, category) : true;
    });

  const deduped = dedupeCommercialProducts(merged, limit * 2);
const ranked = rankLocalFallbackProducts(deduped, query);

return ranked.slice(0, limit);
}
