// ======================================================
// CENTRAL SCORE ENGINE ã VALORA/MIA
// ======================================================
// FunûÏûÈo central para transformar product_specs em score organizado.
// Importante:
// - Ainda NûO substitui ranking.
// - Ainda NûO remove heurûÙsticas antigas.
// - Apenas cria a fonte oficial padronizada.
// - Supabase/product_specs ûˋ a fonte principal.
// - Se faltar dado, retorna null com seguranûÏa.
function toNumberOrNull(value) {
  if (value === null || value === undefined) {
    return null;
  }

  const number = Number(value);

  if (Number.isNaN(number)) {
    return null;
  }

  return number;
}
function normalizeScoreValue(value) {
  const number = toNumberOrNull(value);

  if (number === null) return null;

  if (number < 0) return 0;
  if (number > 100) return 100;

  return Math.round(number);
}

function buildScoreEngineFromSpecs(specs = null) {
  if (!specs) {
    return {
      source: "none",
      hasTrustedScores: false,
      scores: {
        performance: null,
        camera: null,
        battery: null,
        screen: null,
        longevity: null,
        value: null
      },
      raw: null
    };
  }

  const scores = {
    performance: normalizeScoreValue(specs.performance_score),
    camera: normalizeScoreValue(specs.camera_score),
    battery: normalizeScoreValue(specs.battery_score),
    screen: normalizeScoreValue(specs.screen_score),
    longevity: normalizeScoreValue(specs.longevity_score),
    value: normalizeScoreValue(specs.value_score)
  };

  const hasTrustedScores = Object.values(scores).some(
    (score) => score !== null
  );

  return {
    source: specs.category ? `${specs.category}_product_specs` : "product_specs",
    hasTrustedScores,
    scores,
    bands: {
      performance: getScoreBand(scores.performance),
      camera: getScoreBand(scores.camera),
      battery: getScoreBand(scores.battery),
      screen: getScoreBand(scores.screen),
      longevity: getScoreBand(scores.longevity),
      value: getScoreBand(scores.value)
    },
    interpretations: {
      performance: getScoreInterpretation("performance_score", scores.performance),
      camera: getScoreInterpretation("camera_score", scores.camera),
      battery: getScoreInterpretation("battery_score", scores.battery),
      screen: getScoreInterpretation("screen_score", scores.screen),
      longevity: getScoreInterpretation("longevity_score", scores.longevity),
      value: getScoreInterpretation("value_score", scores.value)
    },
    raw: specs
  };
}

function getScoreEngineValue(scoreEngine = null, priority = "") {
  if (!scoreEngine?.scores) return null;

  if (priority === "performance") return scoreEngine.scores.performance;
  if (priority === "camera") return scoreEngine.scores.camera;
  if (priority === "battery") return scoreEngine.scores.battery;
  if (priority === "screen") return scoreEngine.scores.screen;
  if (priority === "longevity") return scoreEngine.scores.longevity;
  if (priority === "value") return scoreEngine.scores.value;

  return null;
}

function getTrustedSpecsPriorityValue(product = {}, priority = "") {
  const scoreEngine =
    product.scoreEngine ||
    buildScoreEngineFromSpecs(product.trustedSpecs || null);

  if (!scoreEngine?.hasTrustedScores) return null;

  if (priority === "storage") {
    const storage = toNumberOrNull(product?.trustedSpecs?.storage_gb);

    if (storage !== null) return storage;
    return null;
  }

  return getScoreEngineValue(scoreEngine, priority);
}

function isGamingProtectedContext(querySignals = {}, query = "") {
  const signals =
    querySignals && typeof querySignals === "object"
      ? querySignals
      : detectMiaUsageContextSignals(query);

  return !!signals?.gaming;
}

function isBatteryProtectedContext(querySignals = {}, query = "") {
  const signals =
    querySignals && typeof querySignals === "object"
      ? querySignals
      : detectMiaUsageContextSignals(query);

  return !!(signals?.batteryPriority || signals?.awayFromHome);
}

function buildRankingScoreBreakdown({
  product = {},
  query = "",
  priority = "",
  rankingProfile = ""
} = {}) {
  const scoreEngine =
    product.scoreEngine ||
    buildScoreEngineFromSpecs(product.trustedSpecs || null);
  const scores = scoreEngine?.scores || {};
  const isGamingProfile = rankingProfile === "gaming_performance";
  const isBatteryProfile = rankingProfile === "battery_autonomy";
  const effectivePriority = isGamingProfile
    ? "performance"
    : isBatteryProfile
      ? "battery"
      : priority;

  const valueWeight = isGamingProfile ? 0.5 : isBatteryProfile ? 0.6 : 1.4;
  const performanceWeight = isGamingProfile ? 1.8 : isBatteryProfile ? 0.7 : 1.1;
  const batteryWeight = isBatteryProfile ? 1.8 : 0.9;
  const batteryTierAdjustment = isBatteryProfile
    ? getBatteryProductTierAdjustment(product)
    : 0;

  const generalScore =
    (Number(scores.value) || 0) * valueWeight +
    (Number(scores.performance) || 0) * performanceWeight +
    (Number(scores.battery) || 0) * batteryWeight +
    (Number(scores.camera) || 0) * 0.8 +
    (Number(scores.screen) || 0) * 0.8 +
    (Number(scores.longevity) || 0) * 1.1;

  const priorityValue = getTrustedSpecsPriorityValue(
    { ...product, scoreEngine },
    effectivePriority
  );

  let total = 0;

  if (scoreEngine?.hasTrustedScores) {
    if (effectivePriority && priorityValue !== null && priorityValue !== undefined) {
      const priorityMultiplier = isGamingProfile ? 65 : isBatteryProfile ? 65 : 55;
      const generalMultiplier = isGamingProfile ? 1.25 : isBatteryProfile ? 0.95 : 1.15;
      total += Number(priorityValue) * priorityMultiplier;
      total += generalScore * generalMultiplier;
    } else {
      total += generalScore;
    }

    total += 300;
  }

  if (isGamingProfile) {
    total -= getGamingProductTierPenalty(product.product_name);
  }

  if (isBatteryProfile) {
    total += batteryTierAdjustment;
  }

  return {
    profile: rankingProfile || "default",
    priority: effectivePriority || priority || "",
    battery: Number(scores.battery) || 0,
    performance: Number(scores.performance) || 0,
    value: Number(scores.value) || 0,
    priorityValue: Number(priorityValue) || 0,
    generalScore: Math.round(generalScore * 100) / 100,
    batteryTierAdjustment,
    total: Math.round(total * 100) / 100
  };
}

function getBatteryProductTierAdjustment(product = {}) {
  const scoreEngine =
    product.scoreEngine ||
    buildScoreEngineFromSpecs(product.trustedSpecs || null);
  const scores = scoreEngine?.scores || {};
  const battery = Number(scores.battery) || 0;
  const performance = Number(scores.performance) || 0;
  const value = Number(scores.value) || 0;

  if (!scoreEngine?.hasTrustedScores || !battery) return 0;

  const batteryLead = battery - Math.max(performance * 0.92, value * 0.75);

  if (batteryLead >= 10) return Math.min(90, Math.round(batteryLead * 3));
  if (performance > battery + 2) {
    return -Math.min(80, Math.round((performance - battery) * 6));
  }
  if (batteryLead <= -8) return Math.max(-75, Math.round(batteryLead * 4));

  return 0;
}

function getGamingProductTierPenalty(productName = "") {
  const title = normalizeQuery(productName || "");
  let penalty = 0;

  if (/\bs25 fe\b|\bgalaxy s\d+ fe\b|\bfe\b/.test(title)) {
    penalty += 80;
  }

  if (/galaxy a[0-3][0-9]|a1[5-9]|a2[0-5]|moto g[0-9]|moto e|redmi note|galaxy a0/.test(title)) {
    penalty += 65;
  }

  if (/samsung galaxy s25\b|galaxy s25\b|s25\+|s25 ultra/.test(title) && !/\bfe\b/.test(title)) {
    penalty -= 45;
  }

  return penalty;
}

function calculateTrustedSpecsRankingScore({
  product = {},
  query = "",
  priority = "",
  index = 0,
  rankingProfile = ""
} = {}) {
  const scoreEngine =
    product.scoreEngine ||
    buildScoreEngineFromSpecs(product.trustedSpecs || null);

  const scores = scoreEngine?.scores || {};
  const price = parsePrice(product.price);
  const budget = extractBudget(query);
  const isGamingProfile = rankingProfile === "gaming_performance";
  const isBatteryProfile = rankingProfile === "battery_autonomy";
  const effectivePriority = isGamingProfile
    ? "performance"
    : isBatteryProfile
      ? "battery"
      : priority;

  let score = 0;

  const hasTrustedScores = !!scoreEngine?.hasTrustedScores;

  const valueWeight = isGamingProfile ? 0.5 : isBatteryProfile ? 0.6 : 1.4;
  const performanceWeight = isGamingProfile ? 1.8 : isBatteryProfile ? 0.7 : 1.1;
  const batteryWeight = isBatteryProfile ? 1.8 : 0.9;

  const generalScore =
    (
      (scores.value || 0) * valueWeight +
      (scores.performance || 0) * performanceWeight +
      (scores.battery || 0) * batteryWeight +
      (scores.camera || 0) * 0.8 +
      (scores.screen || 0) * 0.8 +
      (scores.longevity || 0) * 1.1
    );

  const priorityValue = getTrustedSpecsPriorityValue(
    {
      ...product,
      scoreEngine
    },
    effectivePriority
  );

  if (hasTrustedScores) {
    if (effectivePriority && priorityValue !== null && priorityValue !== undefined) {
      const priorityMultiplier = isGamingProfile ? 65 : isBatteryProfile ? 65 : 55;
      const generalMultiplier = isGamingProfile ? 1.25 : isBatteryProfile ? 0.95 : 1.15;
      score += Number(priorityValue) * priorityMultiplier;
      score += generalScore * generalMultiplier;
    } else {
      score += generalScore;
    }

    score += 300;
  }

  if (product.link) score += 30;
  if (product.thumbnail) score += 20;
  if (product.price) score += 25;

  if (!Number.isNaN(price) && budget) {
    if (price <= budget) score += 80;
    else if (price <= budget * 1.15) score += 25;
    else if (price > budget * 1.35) score -= 120;
  }

  if (/usado|seminovo|recondicionado|vitrine/i.test(product.product_name || "")) {
    score -= 50;
  }

  if (isGamingProfile) {
    score -= getGamingProductTierPenalty(product.product_name);

    const title = normalizeQuery(product.product_name || "");
    if (/\bfe\b|galaxy a[0-9]|moto g|redmi note/.test(title)) {
      score -= 60;
    }
  }

  if (isBatteryProfile) {
    score += getBatteryProductTierAdjustment({
      ...product,
      scoreEngine
    });
  }

  score -= index * 0.01;

  return score;
}

// ======================================================
// MIA REASONING ENGINE v1 ã SCORE SIGNALS
// ======================================================
// Transforma scoreEngine/trustedSpecs em sinais internos de decisûÈo.
// Nesta etapa, ainda NûO muda resposta final.
// Serve como base proprietûÀria para explicar por que um produto venceu.

function buildReasoningSignalFromScores({
  scoreEngine = null,
  trustedSpecs = null,
  priority = ""
} = {}) {
  const scores = scoreEngine?.scores || {};

  const scoreLabels = {
    performance: "desempenho",
    camera: "cûÂmera",
    battery: "bateria",
    screen: "tela",
    longevity: "longevidade",
    value: "custo-benefûÙcio",
    storage: "armazenamento"
  };

  const normalizedScores = [
    { key: "performance", label: scoreLabels.performance, value: toNumberOrNull(scores.performance) },
    { key: "camera", label: scoreLabels.camera, value: toNumberOrNull(scores.camera) },
    { key: "battery", label: scoreLabels.battery, value: toNumberOrNull(scores.battery) },
    { key: "screen", label: scoreLabels.screen, value: toNumberOrNull(scores.screen) },
    { key: "longevity", label: scoreLabels.longevity, value: toNumberOrNull(scores.longevity) },
    { key: "value", label: scoreLabels.value, value: toNumberOrNull(scores.value) }
  ].filter((item) => item.value !== null);

  const strongestSignals = normalizedScores
    .filter((item) => item.value >= 75)
    .sort((a, b) => b.value - a.value)
    .slice(0, 3);

  const weakSignals = normalizedScores
    .filter((item) => item.value < 60)
    .sort((a, b) => a.value - b.value)
    .slice(0, 3);

  let prioritySignal = null;

  if (priority === "storage") {
    const storageValue = toNumberOrNull(trustedSpecs?.storage_gb);

    prioritySignal = {
      key: "storage",
      label: scoreLabels.storage,
      value: storageValue,
      source: storageValue !== null ? "trusted_specs" : "missing"
    };
  } else if (priority) {
    const priorityValue = getScoreEngineValue(scoreEngine, priority);

    prioritySignal = {
      key: priority,
      label: scoreLabels[priority] || priority,
      value: toNumberOrNull(priorityValue),
      source: priorityValue !== null && priorityValue !== undefined ? "scoreEngine" : "missing"
    };
  }

  const tieSignals = normalizedScores
    .filter((item) => item.value >= 65 && item.value <= 75)
    .map((item) => ({
      ...item,
      reason: `${item.label} fica em uma faixa intermediûÀria/segura, sem vantagem absoluta.`
    }));

  const tradeoffs = weakSignals.map((item) => ({
    key: item.key,
    label: item.label,
    value: item.value,
    reason: `${item.label} pode ser um ponto de atenûÏûÈo na decisûÈo.`
  }));

  return {
    hasTrustedReasoning: !!scoreEngine?.hasTrustedScores,
    scoreSource: scoreEngine?.source || "unknown",
    strongestSignals,
    weakSignals,
    prioritySignal,
    tieSignals,
    tradeoffs,
    rawScores: scores
  };
}

// ======================================================
// SPECS IMPACT TRANSLATION ENGINE ã ETAPA 2.5
// ======================================================
// Transforma specs/scores em consequûˆncia real de uso.
// NûÈo decide vencedor.
// NûÈo inventa dados.
// NûÈo depende da LLM.
// A LLM apenas verbaliza estes impactos proprietûÀrios.

function getMiaAxisLabel(axis = "") {
  const labels = {
    performance: "desempenho",
    battery: "bateria",
    camera: "cûÂmera",
    screen: "tela",
    longevity: "longevidade",
    value: "custo-benefûÙcio",
    storage: "armazenamento"
  };

  return labels[axis] || axis || "";
}

function getMiaScoreStrengthLabel(score = null) {
  const value = toNumberOrNull(score);

  if (value === null) return "";
  if (value >= 85) return "muito forte";
  if (value >= 75) return "forte";
  if (value >= 65) return "seguro";
  if (value >= 55) return "mediano";
  return "limitado";
}

// ãããããããããããããããããããããããããããããããããããããããããããããããããããããããããããããããããããããããããããããã
// ARQUITETURA DE ARQUûTIPOS COGNITIVOS ã MIA v2.5 (4-PLANE MODEL)
//
// PLANO A ã Arquûˋtipo Humano (universal, sem categoria)
//   Entidade cognitiva estûÀvel. TensûÈo humana e motivaûÏûÈo psicolû°gica
//   independentes de produto. NûÈo contûˋm regex. NûÈo menciona "celular".
//   Referûˆncia: MIA_ARCHETYPE_IDS (abaixo).
//
// PLANO B ã Sinal de Vertical (detectores locais da categoria)
//   Regex e heurûÙsticas acopladas ao domûÙnio. Cada sinal "aponta para"
//   um arquûˋtipo ã nûÈo "ûˋ" um arquûˋtipo.
//   Referûˆncia: detectMiaUsageContextSignals (abaixo).
//
// PLANO C ã Peso de Eixo (arquûˋtipo û vertical ã axis weights)
//   Quanto cada eixo tûˋcnico importa para cada arquûˋtipo.
//   Referûˆncia: resolveMiaConsequenceContextKey + MIA_CONTEXTUAL_INTENT_RULES.
//
// PLANO D ã Consequûˆncia de DomûÙnio (arquûˋtipo û eixo û vertical ã narrativa)
//   Consequûˆncias e sensaûÏûçes escritas na linguagem da categoria.
//   ûnico plano que menciona "celular", "tomada", "partida".
//   Referûˆncia: MIA_CONSEQUENCE_MAP_V1 + buildMiaHumanImpactExpansion.
//
// MVP v1 ã 7 arquûˋtipos ativos: power_intensity, productivity_work,
//   casual_comfort, mobility_freedom, longevity_investment,
//   budget_rational, safety_antiregret.
// ãããããããããããããããããããããããããããããããããããããããããããããããããããããããããããããããããããããããããããããã

// Plano A ã Arquûˋtipos universais MVP (referûˆncia documental ã sem lû°gica).
// Cada entrada: archetypeId ã { tension, currentSignal }
// currentSignal = chave no retorno de detectMiaUsageContextSignals (Plano B).
const MIA_ARCHETYPE_IDS = {
  power_intensity:      { tension: "quero extrair o mûÀximo ã o dispositivo nûÈo pode ser o gargalo",               currentSignal: "gaming" },
  productivity_work:    { tension: "preciso que funcione ã falha no trabalho tem consequûˆncia real",               currentSignal: "heavyUse" },
  casual_comfort:       { tension: "sû° quero que funcione sem pensar ã sem fricûÏûÈo, sem esforûÏo",                  currentSignal: "casual" },
  mobility_freedom:     { tension: "estou em movimento ã preciso de independûˆncia da infraestrutura base",         currentSignal: "awayFromHome" },
  longevity_investment: { tension: "compro para durar ã nûÈo quero arrependimento de mûˋdio prazo",                  currentSignal: "longTerm" },
  budget_rational:      { tension: "quero a decisûÈo inteligente ã nûÈo a mais barata, a mais racional",             currentSignal: "priceSensitive" },
  safety_antiregret:    { tension: "nûÈo quero errar ã a incerteza da decisûÈo me paralisa",                         currentSignal: "regretFear" },
  // Fase 2 (defer): creator_expression, reliability_trust
  // Fase 3 (defer com guardrails): status_premium
  // Descartado: practicality (ûˋ o estado default, nûÈo um arquûˋtipo)
  // Fundidos: simplicity_lowmaintenance ã casual_comfort | economy_of_time ã productivity_work
};

// Plano B ã DetecûÏûÈo de sinais da vertical smartphone.
// Cada sinal mapeia para um archetypeId em MIA_ARCHETYPE_IDS.
// IMPORTANTE: estes sinais sûÈo detectores locais, nûÈo os arquûˋtipos em si.
// "gaming" nûÈo ûˋ power_intensity ã ûˋ como power_intensity se manifesta em smartphone.
function detectMiaUsageContextSignals(query = "") {
  const normalized = normalizeQuery(query || "");

  return {
    // ã power_intensity: uso que empurra o dispositivo ao limite
    // "pesado" removido: ûˋ intensidade genûˋrica (ã heavyUse), nûÈo sinal de jogo.
    // Jogos sûÈo identificados por termos especûÙficos; "trabalho pesado" nûÈo ûˋ gaming.
    // "jogos" (plural) adicionado ã "para jogos" ûˋ expressûÈo muito comum.
    gaming:
      /\b(jogo|jogos|jogar|games|game|cod|free fire|genshin|pubg|fortnite|jogos pesados|jogo pesado)\b/i.test(normalized) ||
      /\b(pesado|pesada)\b.*\b(jogo|jogos|jogar)\b/i.test(normalized) ||
      /\b(jogo|jogos|jogar)\b.*\b(pesado|pesada)\b/i.test(normalized),

    // ã productivity_work: aparelho como ferramenta profissional + economy_of_time (fundido)
    // HLU Fase 1: "trav" (prefixo quebrado por \b) substituûÙdo por formas conjugadas reais.
    // "trava|travando|travar|travou|travamento" cobrem o vocabulûÀrio de frustraûÏûÈo com fluidez.
    // HLU Fase 4 (creator-adjacent): "editar|ediûÏûÈo|editor|render" cobrem criadores de conteû¤do profissional
    // e usuûÀrios que editam vûÙdeo/foto ã uso intenso real, nûÈo casual.
    // "celular direto|mil coisas ao mesmo tempo|uso direto" capturam multitarefa informal humana
    // sem exigir a palavra literal "multitarefa".
    // "produûÏûÈo de conteudo|edicao de video" sûÈo formas explicitamente profissionais.
    heavyUse:
      /\b(uso bastante|uso intenso|muito uso|multitarefa|trabalho|estudo|trava|travando|travar|travou|travamento|trave|fluidez|rûÀpido|rapido|pesado|editar|ediûÏûÈo|edicao|editor|edito|producao|producûÈo|criar video|criar videos|render|renderizar|celular direto|uso direto|fazer tudo ao mesmo tempo|mil coisas ao mesmo tempo|mil coisa ao mesmo tempo|producao de conteudo|producûÈo de conteudo|edicao de video|editar video|editar foto|uso profissional|produtividade)\b/i.test(normalized),

    // ã casual_comfort: uso sem fricûÏûÈo + simplicity_lowmaintenance (fundido)
    // HLU Fase 1: vocabulûÀrio expandido para cobrir uso implûÙcito e contexto familiar/acadûˆmico.
    // "simples|basico" capturam quem nûÈo sabe descrever tecnicamente.
    // "dia a dia|uso normal" capturam uso cotidiano sem intensidade.
    // "minha mae|meu pai|faculdade|estudar|whatsapp" capturam contexto de uso real indireto.
    // HLU Fase 2: entretenimento cotidiano (netflix|series|filmes|streaming|maratonar) adicionado.
    // Consumo de mûÙdia ûˋ casual_comfort ã nûÈo performance, nûÈo creator_expression.
    // HLU Fase 4: "criar conteudo" e "conteudo" genûˋrico REMOVIDOS de casual para evitar
    // falso positivo com "editar conteû¤do" (uso profissional ã  casual). Consumo social
    // continua coberto por "stories|reels|tiktok|instagram".
    casual:
      /\b(casual|redes sociais|stories|reels|social|midia|tiktok|instagram|youtube|simples|basico|bûÀsico|dia a dia|uso normal|minha mae|meu pai|faculdade|estudar|whatsapp|netflix|series|filmes|streaming|maratonar)\b/i.test(normalized),

    // ã mobility_freedom: independûˆncia da infraestrutura (tomada, Wi-Fi, cabo)
    awayFromHome:
      /\b(fora de casa|longe de casa|longe de tomada|rua|viajo|viagem|4g|5g|ûÇnibus|onibus)\b/i.test(normalized),

    // ã longevity_investment: horizonte temporal longo, compra como investimento
    // HLU Fase 1: conjugaûÏûçes de "envelhecer" adicionadas ã "envelheûÏa" ûˋ a forma mais natural
    // em perguntas/desejos e nûÈo era coberta. "durar anos" cobre variante sem "bastante".
    // "envelheûÏa" apû°s normalizaûÏûÈo NFD vira "envelheca" (ûÏ ã c removido).
    // Listamos ambas as formas para cobrir textos normalizados e nûÈo normalizados.
    longTerm:
      /\b(durar|muitos anos|longo prazo|ficar anos|nûÈo quero trocar|nao quero trocar|envelhecer|envelheûÏa|envelheca|envelhece|envelhecendo|dure|durar bastante|durar anos)\b/i.test(normalized),

    // ã safety_antiregret: medo de errar na decisûÈo, necessidade de certeza
    // STEP 2 ativo: safetyAntiregret propagado via buildMiaHumanImpactExpansion
    //   ã buildMiaConsequenceNarrativeBlocks (opening calibrado, tradeoffHonest obrigatû°rio)
    //   ã buildMiaHumanConsequenceReasoning (verbalizationContract.safetyAntiregret)
    // HLU Fase 1: "arrepend" (prefixo quebrado por \b) expandido com formas reais.
    // "inseguro|insegura" capturam hesitaûÏûÈo sem usar "medo".
    // "nao sei qual|nao entendo" capturam dû¤vida expressa de forma informal.
    regretFear:
      /\b(medo|arrepend|arrepender|arrependimento|arrependi|dor de cabeûÏa|dor de cabeca|nûÈo quero errar|nao quero errar|inseguro|insegura|nao sei qual|nao entendo|seguro|seguranûÏa|seguranca)\b/i.test(normalized),

    // ã budget_rational: raciocûÙnio de valor percebido, nûÈo sû° preûÏo baixo
    // HLU Fase 1: vocabulûÀrio de orûÏamento expandido com linguagem humana real.
    // HLU Fase 3: "atoa/û  toa", "jogar dinheiro fora", "sem necessidade", "so gastar" adicionados.
    // Cobrem: "nûÈo quero gastar dinheiro atoa", "jogar dinheiro fora", "economico".
    priceSensitive:
      /\b(barato|preûÏo|preco|custo|vale a pena|economizar|orûÏamento|orcamento|gastar|grana|dinheiro|vale pagar|pagar mais|mil reais|menos de mil|ate mil|orcamento apertado)\b/i.test(normalized) ||
      /\b(atoa|û  toa|a toa|jogar fora|jogando fora|desperdicar|desperdiûÏar|desperdicio|desperdûÙcio|sem necessidade|so gastar|sû° gastar|gastar demais|pagar caro|pagar demais)\b/i.test(normalized),

    // ã battery_priority: intenûÏûÈo de autonomia sem exigir mobilidade explûÙcita.
    // HLU Fase 2: cobre usuûÀrios que querem boa bateria no dia a dia sem citar viagem/rua.
    // "bateria|autonomia" sûÈo o vocabulûÀrio direto de bateria.
    // "dura pouco|carregar toda hora|bateria acaba|pouca bateria" capturam frustraûÏûÈo com autonomia.
    // "carregando sempre|sem bateria" capturam o estado negativo que o usuûÀrio quer evitar.
    // awayFromHome continua prioridade mûÀxima dentro do eixo battery.
    // "carregando toda hora" (gerû¤ndio) e "carregar toda hora" (infinitivo) ambos coberûÏos.
    batteryPriority:
      /\b(bateria|autonomia|dura pouco|carregar toda hora|carregando toda hora|carregando sempre|sem bateria|bateria acaba|pouca bateria)\b/i.test(normalized),

    // ã brand rejection: usuûÀrio expressa rejeiûÏûÈo explûÙcita a uma marca
    // HLU Fase 3: captura resistûˆncia de marca sem suprimir recomendaûÏûÈo ã sinaliza ao pipeline
    // para depriorizar essa marca e iniciar exploraûÏûÈo conversacional ou perguntar motivo.
    // "nunca me convenceu" / "nûÈo gosto" / "me decepcionou" / "nûÈo confio" / "ruim pra mim"
    brandRejectionApple:
      /\b(iphone nunca|apple nunca|nao gosto.*iphone|nûÈo gosto.*iphone|nao gosto.*apple|nûÈo gosto.*apple|iphone me decepcionou|apple me decepcionou|nao confio.*apple|nûÈo confio.*apple|nao curto.*iphone|nûÈo curto.*iphone|iphone nao|iphone nûÈo)\b/i.test(normalized) ||
      /\b(nao quero.*iphone|nûÈo quero.*iphone|evitar.*iphone|fora.*iphone)\b/i.test(normalized),

    brandRejectionSamsung:
      /\b(samsung nunca|nao gosto.*samsung|nûÈo gosto.*samsung|samsung me decepcionou|nao confio.*samsung|nûÈo confio.*samsung|nao curto.*samsung|nûÈo curto.*samsung|samsung nao|samsung nûÈo)\b/i.test(normalized) ||
      /\b(nao quero.*samsung|nûÈo quero.*samsung|evitar.*samsung|fora.*samsung)\b/i.test(normalized),

    brandRejectionXiaomi:
      /\b(xiaomi nunca|redmi nunca|nao gosto.*xiaomi|nûÈo gosto.*xiaomi|xiaomi me decepcionou|nao confio.*xiaomi|nûÈo confio.*xiaomi|nao confio.*redmi|nûÈo confio.*redmi)\b/i.test(normalized) ||
      /\b(nao quero.*xiaomi|nûÈo quero.*xiaomi|evitar.*xiaomi|fora.*xiaomi)\b/i.test(normalized)
  };
}

