function applyConversationalMemoryAwareResponse(lines = [], {
  messages = [],
  winnerName = "",
  priorityLabel = "",
  reasonAxisLabel = "",
  mirror = {}
} = {}) {
  const recentReplies = getRecentAssistantReplies(messages);

  if (!recentReplies.length || !Array.isArray(lines)) {
    return lines;
  }

  const recentThemes = getRecentlyUsedSemanticThemes(messages);
  const usedThemes = [...recentThemes];

  return lines
    .map((line, index) => {
      const cleanLine = String(line || "").trim();

      if (!cleanLine) return "";

      const repeatsExactLine = lineWasRecentlyUsed(cleanLine, recentReplies);
      const repeatsSemanticTheme = lineRepeatsRecentSemanticTheme(cleanLine, usedThemes);

      if (!repeatsExactLine && !repeatsSemanticTheme) {
        usedThemes.push(...detectSemanticResponseThemes(cleanLine));
        return cleanLine;
      }

      const replacement = repeatsSemanticTheme
        ?          buildSemanticMemoryReplacementLine({
            line: cleanLine,
            winnerName,
            priorityLabel,
            reasonAxisLabel,
            usedThemes,
            index,
            mirror
          })
        : buildMemoryAwareReplacementLine({
            line: cleanLine,
            winnerName,
            priorityLabel,
            index,
            mirror
          });

      usedThemes.push(...detectSemanticResponseThemes(replacement));

      return replacement;
    })
    .filter(Boolean);
}

function getHumanDecisionTurnSeed({
  query = "",
  messages = [],
  winnerName = "",
  priority = ""
} = {}) {
  const recentUserMessages = Array.isArray(messages)
    ? messages
        .filter((message) => message?.role === "user")
        .slice(-6)
        .map((message, index) => `${index}:${message.content || message.text || ""}`)
        .join("|")
    : "";

  return [
    query || "",
    recentUserMessages,
    winnerName || "",
    priority || "",
    Date.now().toString().slice(-4)
  ].join("|");
}

