function buildMiaHumanReasonsLine({
  reasons = [],
  winnerName = "",
  priority = "",
  winnerContext = null
} = {}) {
  const validReasons = Array.isArray(reasons)
    ? reasons.filter((reason) => reason?.label)
    : [];

  if (!validReasons.length || !winnerName) return "";

  const labels = validReasons
    .map((reason) => reason.label)
    .slice(0, 2);

  const seed = [
    winnerName,
    priority,
    labels.join("|")
  ].join("|");

    const languageContext =
    winnerContext || getProductLanguageContext(winnerName);

  const subjectPronoun = languageContext.pronoun || "ele";
  const objectPronoun = languageContext.objectPronoun || "ele";
  const possessivePronoun = languageContext.possessive || "dele";

  if (labels.length === 1) {
    const reasonLabel = labels[0];

        return pickMiaHumanLine([
      `Principalmente por ${reasonLabel}.`,
      `${reasonLabel} pesa bastante aqui.`,
      `O ponto que coloca ${objectPronoun} na frente ûˋ mais ${reasonLabel}.`,
      `${subjectPronoun.charAt(0).toUpperCase() + subjectPronoun.slice(1)} acaba ficando melhor justamente em ${reasonLabel}.`
    ], seed);
  }

  const first = labels[0];
  const second = labels[1];

      const firstCapitalized = capitalizeFirstHumanChar(first);

  return pickMiaHumanLine([
    `${subjectPronoun.charAt(0).toUpperCase() + subjectPronoun.slice(1)} leva vantagem principalmente em ${first} e ${second}.`,
    `${firstCapitalized} e ${second} pesam bastante pra ${objectPronoun}.`,
    `O que coloca ${objectPronoun} na frente ûˋ mais ${first} e ${second}.`,
    `Juntando ${first} e ${second}, ${subjectPronoun} acaba ficando mais forte.`
  ], seed);
}

