// ======================================================
// STRUCTURED VISUAL BREAKDOWN DETECTOR ã ETAPA 5.2.5.6.1
// ======================================================
// Detecta quando o usuûÀrio quer uma resposta visual em blocos:
// prû°s/contras, pontos positivos/negativos, lado bom/ruim,
// comparaûÏûÈo detalhada, resumo em lista etc.
// Isso libera mais emojis, mas sû° nesse modo.

function detectStructuredVisualBreakdownIntent(query = "") {
  const q = normalizeQuery(query || "");

  if (!q) return false;

  return /\b(pontos positivos|pontos negativos|positivo|negativo|pr[oû°]s|contras|pros e contras|pr[oû°]s e contras|lado bom|lado ruim|bom e ruim|vantagens|desvantagens|compare em lista|comparar em lista|lista|resumo em lista|detalhado|detalhada|comparaûÏûÈo detalhada|comparacao detalhada|me explica melhor|explica melhor|quais os pontos|ponto forte|ponto fraco|vale a pena|diferenûÏas|diferencas)\b/i.test(q);
}

