// RESPONSE COMPLETION STABILITY ENGINE ã ETAPA 5.2.5.1
// ======================================================
// Evita respostas cortadas por limite baixo de tokens.
// NûÈo muda vencedor, nûÈo muda reasoning e nûÈo cria frase pronta.

// ======================================================
// STRICT DECISION ENGINE REPLY ã ETAPA 4.1
// CONTEXTUAL PRIORITY ENGINE
// ======================================================
// Objetivo:
// - Manter Data Layer como fonte oficial.
// - Manter Decision Engine mandando.
// - Fazer a prioridade do usuûÀrio mudar tese, abertura, tradeoff e veredito.
// - Transformar resposta de "melhor geral" para "melhor para o seu uso".
// - NûO mexe em preûÏo, cache, provider, Data Layer ou ranking.

function getDecisionEngineAxisLabel(axis = "") {
  const labels = {
    performance: "desempenho",
    camera: "cûÂmera",
    battery: "bateria",
    screen: "tela",
    longevity: "longevidade",
    value: "custo-benefûÙcio",
    storage: "armazenamento"
  };

  return labels[axis] || axis;
}

function getDecisionEngineScore(profile = null, axis = "") {
  const value =
    profile?.trustedScores?.[axis] ??
    profile?.scoreEngine?.scores?.[axis] ??
    profile?.product?.scoreEngine?.scores?.[axis] ??
    null;

  const number = toNumberOrNull(value);

  return number === null ? null : number;
}

function getDecisionEngineSpecs(profile = null) {
  return (
    profile?.trustedSpecs ||
    profile?.product?.trustedSpecs ||
    {}
  );
}

function buildDecisionEngineAxisAdvantages(winner = null, loser = null) {
  const axes = [
    "performance",
    "camera",
    "battery",
    "screen",
    "longevity",
    "value"
  ];

  return axes
    .map((axis) => {
      const winnerScore = getDecisionEngineScore(winner, axis);
      const loserScore = getDecisionEngineScore(loser, axis);

      if (winnerScore === null || loserScore === null) return null;

      return {
        axis,
        label: getDecisionEngineAxisLabel(axis),
        winnerScore,
        loserScore,
        gap: winnerScore - loserScore
      };
    })
    .filter(Boolean)
    .sort((a, b) => Math.abs(b.gap) - Math.abs(a.gap));
}

function getDecisionGapIntensity(gap = 0) {
  const absGap = Math.abs(Number(gap || 0));

  if (absGap >= 15) return "grande";
  if (absGap >= 8) return "clara";
  if (absGap >= 4) return "moderada";

  return "pequena";
}

function getMiaSignatureConviction(decisionStrength = 0) {
  if (decisionStrength >= 15) {
    return {
      level: "strong",
      phrase: "aqui eu teria bastante confianûÏa na escolha",
      verdictTone: "sem muita dû¤vida"
    };
  }

  if (decisionStrength >= 8) {
    return {
      level: "clear",
      phrase: "aqui eu jûÀ vejo um caminho bem claro",
      verdictTone: "com boa seguranûÏa"
    };
  }

  if (decisionStrength >= 4) {
    return {
      level: "moderate",
      phrase: "a vantagem existe, mas nûÈo ûˋ uma surra",
      verdictTone: "com uma ressalva"
    };
  }

  return {
    level: "close",
    phrase: "aqui eu nûÈo trataria como uma vitû°ria absoluta",
    verdictTone: "por pouco"
  };
}

