// ======================================================
// MIA BEHAVIOR ENFORCEMENT LAYER ã ETAPA 1.1.2
// ======================================================
// Camada proprietûÀria de enforcement comportamental.
// NûÈo decide vencedor.
// NûÈo altera ranking.
// NûÈo inventa dados.
// NûÈo depende de uma LLM especûÙfica.
// A LLM continua sendo apenas camada de linguagem.

function buildMiaBehaviorEnforcementLayer({
  query = "",
  miaReasoningProfile = {},
  priority = "",
  winnerName = "",
  loserName = ""
} = {}) {
  const intentBehavior = miaReasoningProfile?.intentBasedBehavior || {};
  const depthControl = intentBehavior?.depthControl || {};

  const forbiddenOpenings = [
    "para quem precisa",
    "para quem busca",
    "se vocûˆ procura",
    "considerando que vocûˆ",
    "considerando suas necessidades",
    "analisando os dois",
    "entre os dois",
    "em termos de",
    "quando falamos de"
  ];

  const forbiddenConnectors = [
    "alûˋm disso",
    "portanto",
    "dessa forma",
    "em conclusûÈo",
    "vale ressaltar",
    "ûˋ importante destacar",
    "no geral",
    "de modo geral"
  ];

  const forbiddenReviewStyle = [
    "equipado com",
    "ele oferece",
    "ele possui",
    "conta com",
    "se destaca em",
    "proporciona uma experiûˆncia",
    "garantindo uma experiûˆncia",
    "ideal para usuûÀrios que",
    "excelente opûÏûÈo para quem"
  ];

  const forbiddenClosings = [
    "se precisar de mais alguma coisa",
    "se tiver mais dû¤vidas",
    "espero ter ajudado",
    "posso te ajudar",
    "qualquer coisa ûˋ sû° falar"
  ];

  const userIntentMode = intentBehavior?.userIntentMode || "";
  const reasoningFlow = intentBehavior?.reasoningFlow || "";
  const decisionPosture = intentBehavior?.decisionPosture || "";
  const decisionTension = intentBehavior?.decisionTension || "";
  const responseDensity = intentBehavior?.responseDensity || "";
  const cognitiveCadence = intentBehavior?.cognitiveCadence || "";

  const maxCoreArguments =
    Number(depthControl?.maxCoreArguments || 2) || 2;

  const shouldAvoidFullReview =
    !!depthControl?.shouldAvoidFullReview;

  const shouldExposeTradeoff =
    !!depthControl?.shouldExposeTradeoff;

  const shouldExposeUncertainty =
    !!depthControl?.shouldExposeUncertainty;

  const enforcementMode =
    decisionTension === "conflicted_with_suppression"
      ? "contextual_tradeoff_enforcement"
      : decisionTension === "multi_axis_tradeoff"
        ? "multi_axis_tradeoff_enforcement"
        : decisionTension === "close_call"
          ? "careful_decision_enforcement"
          : decisionPosture === "firm"
            ? "direct_decision_enforcement"
            : "natural_decision_enforcement";

  const openingBehavior =
    reasoningFlow === "tradeoff_first"
      ? "comeûÏar pela decisûÈo aplicada ao cenûÀrio real do usuûÀrio, depois explicar o tradeoff"
      : reasoningFlow === "suppression_aware"
        ? "comeûÏar pelo que pesa no contexto e evitar abrir com eixo suprimido"
        : reasoningFlow === "priority_first"
          ? "comeûÏar pelo eixo prioritûÀrio do usuûÀrio"
          : "comeûÏar pela decisûÈo de forma direta e natural";

  const argumentBehavior =
    shouldAvoidFullReview
      ? "usar apenas argumentos decisivos; nûÈo fazer review completo"
      : "explicar o suficiente para justificar a decisûÈo sem virar anûÀlise tûˋcnica longa";

  const cadenceBehavior =
    cognitiveCadence === "tradeoff_rhythm"
      ? "frases naturais, com contraste claro entre ganho e perda"
      : cognitiveCadence === "careful_rhythm"
        ? "ritmo cauteloso, sem cravar demais se a disputa for prû°xima"
        : cognitiveCadence === "decisive_rhythm"
          ? "ritmo firme e direto"
          : "ritmo consultivo natural";

  return {
    version: "1.1.2-behavior-enforcement-layer",
    active: true,
    providerIndependent: true,
    enforcementMode,

    decisionAuthority: {
      source: "MIA proprietary reasoning",
      llmRole: "language_only",
      mustNotChangeWinner: true,
      mustNotInventEvidence: true,
      mustNotOverrideDataLayer: true
    },

    outputShape: {
      openingBehavior,
      argumentBehavior,
      cadenceBehavior,
      maxCoreArguments,
      shouldAvoidFullReview,
      shouldExposeTradeoff,
      shouldExposeUncertainty,
      avoidBulletList: true,
      avoidMarkdown: true,
      avoidGenericClosing: true,
      avoidReviewStructure: true,
      avoidCorporateTone: true
    },

    naturalBehaviorRules: {
      startWithContextualDecision: true,
      useUserContextAsFrame: true,
      useTradeoffOnlyIfRelevant: shouldExposeTradeoff,
      useShortProductNamesAfterFirstMention: true,
      avoidSpecDump: true,
      avoidTemplateTone: true,
      avoidAssistantTone: true,
      preserveConversationalFlow: true
    },

    blockedLanguage: {
      forbiddenOpenings,
      forbiddenConnectors,
      forbiddenReviewStyle,
      forbiddenClosings
    },

    targetBehavior: {
      userIntentMode,
      reasoningFlow,
      decisionPosture,
      decisionTension,
      responseDensity,
      cognitiveCadence,
      priority,
      winnerName,
      loserName
    }
  };
}

