const MARKET_SCORE_FIELDS = [
  "value_score"
];

function isTechnicalScoreField(field = "") {
  return TECHNICAL_SCORE_FIELDS.includes(field);
}

function isMarketScoreField(field = "") {
  return MARKET_SCORE_FIELDS.includes(field);
}

function getScoreBand(score = null) {
  const value = Number(score);

  if (Number.isNaN(value)) return null;

  if (value >= SCORE_SCALE.excellent.min) return SCORE_SCALE.excellent;
  if (value >= SCORE_SCALE.strong.min) return SCORE_SCALE.strong;
  if (value >= SCORE_SCALE.good.min) return SCORE_SCALE.good;
  if (value >= SCORE_SCALE.basic.min) return SCORE_SCALE.basic;

  return SCORE_SCALE.weak;
}
function getScoreInterpretation(field = "", score = null) {
  const rules = SCORE_INTERPRETATION[field];

  if (!rules) return null;

  const value = Number(score);

  if (Number.isNaN(value)) return null;

  const thresholds = Object.keys(rules)
    .map(Number)
    .sort((a, b) => b - a);

  for (const threshold of thresholds) {
    if (value >= threshold) {
      return rules[threshold];
    }
  }

  return null;
}
function sanitizeBrokenProduct(product = {}) {
  if (!product || typeof product !== "object") {
    return null;
  }

  const title = String(product.product_name || "").trim();

  if (!title || title.length < 4) {
    return null;
  }

  const hasPrice =
    product.price !== null &&
    product.price !== undefined &&
    String(product.price).trim() !== "" &&
    !/indispon/i.test(String(product.price));

  const hasLink =
    product.link &&
    typeof product.link === "string" &&
    product.link.startsWith("http");

  return {
    ...product,

    isBroken:
      !hasPrice ||
      !hasLink,

    qualityPenalty:
      (!hasPrice ? 120 : 0) +
      (!hasLink ? 90 : 0)
  };
}
function normalizeImageBase64(imageBase64 = "") {
  const img = String(imageBase64 || "").trim();

  if (!img) return "";

  if (img.startsWith("data:image/")) {
    return img;
  }

  return `data:image/jpeg;base64,${img}`;
}

