function normalizeProductKey(title = "") {
  return normalizeQuery(title)
    .replace(/[^a-z0-9 ]/g, " ")
    .replace(/\s+/g, " ")
    .trim();
}
function getProductFamilyKey(title = "") {
  const t = normalizeProductKey(title)
    .replace(/\b(4g|5g|128gb|256gb|512gb|1tb|2gb|3gb|4gb|6gb|8gb|12gb|16gb|32gb|ram|rom|tela|camera|cûÂmera|bateria|mah|hz|android|dual|chip|cor|rosa|azul|preto|cinza|verde|branco|lacrado|novo|original)\b/g, " ")
    .replace(/\b(de|da|do|com|sem|para|por|e|a|o|os|as)\b/g, " ")
    .replace(/\s+/g, " ")
    .trim();

  const knownPatterns = [
    /(motorola\s+)?moto\s+g\d+/,
    /realme\s+note\s+\d+/,
    /galaxy\s+a\d+/,
    /samsung\s+galaxy\s+a\d+/,
    /samsung\s+a\s?\d+/,
    /redmi\s+note\s+\d+(\s+pro)?/,
    /infinix\s+hot\s+\d+\w*/,
    /iphone\s+\d+(\s+pro|\s+plus|\s+pro max)?/,
    /poco\s+\w+\d*/,
    /ps5/,
    /xbox\s+series\s+[sx]/,
    /macbook\s+\w+/
  ];

  for (const pattern of knownPatterns) {
    const match = t.match(pattern);
    if (match?.[0]) return match[0].trim();
  }

  return t.split(" ").slice(0, 5).join(" ").trim();
}
// ======================================================
// COMPARISON CONTEXT LOCK ã ETAPA 3
// ======================================================
// Objetivo:
// - Quando o usuûÀrio perguntar "A15 ou G84?", travar esses candidatos.
// - Follow-ups como "qual tem bateria melhor?" continuam comparando sû° eles.
// - NûÈo faz busca ampla nova.
// - NûÈo deixa Redmi/Outro produto entrar aleatoriamente.

function extractComparisonTermsFromQuery(query = "") {
  const raw = String(query || "").trim();

  if (!raw) return [];

  const cleanComparisonTerm = (part = "") =>
    cleanTitle(part)
      .replace(/\b(qual|quais|quem|melhor|pior|vale|mais|menos|tem|pena|entre|comparar|compare|comparaûÏûÈo|comparacao)\b/gi, " ")
      .replace(/\b(celular|smartphone|telefone|aparelho|modelo|opûÏûÈo|opcao)\b/gi, " ")
      .replace(/\b(bateria|autonomia|carga|tomada|desempenho|performance|camera|cûÂmera|foto|fotos|video|vûÙdeo|tela|display|armazenamento|memoria|memû°ria|espaûÏo|espaco|custo|beneficio|benefûÙcio)\b/gi, " ")
      .replace(/[,:;()]/g, " ")
      .replace(/[?!.]/g, " ")
      .replace(/\s+/g, " ")
      .trim();

  const normalizeTerms = (parts = []) => {
    const seen = new Set();

    return parts
      .map((part) => cleanComparisonTerm(part))
      .filter((part) => part.length >= 2)
      .filter((part) => {
        const key = normalizeProductKey(part);
        if (!key || seen.has(key)) return false;
        seen.add(key);
        return true;
      })
      .slice(0, 4);
  };

  const normalizedRaw = raw
    .replace(/\s+x\s+/gi, " vs ")
    .replace(/\s+contra\s+/gi, " vs ")
    .replace(/\s+versus\s+/gi, " vs ");

  const hasDirectComparisonConnector =
    /\b(ou|vs|versus|contra)\b/i.test(normalizedRaw);

  if (hasDirectComparisonConnector) {
    const terms = normalizeTerms(
      normalizedRaw
        .replace(/[?!.]/g, " ")
        .split(/\b(?:ou|vs|versus|contra)\b/i)
    );

    if (terms.length >= 2) {
      console.log("Þ COMPARISON TERMS EXTRAûDOS:", {
        query: raw,
        terms
      });

      return terms;
    }
  }

  const looksLikeMoreQuestion =
    /\b(qual|quais|quem)\b/i.test(raw) &&
    /\b(mais|melhor|maior|dura|aguenta|vale)\b/i.test(raw);

  if (looksLikeMoreQuestion && /\bentre\b/i.test(raw) && /\se\s/i.test(raw)) {
    const afterEntre = raw.split(/\bentre\b/i).pop() || "";
    const beforeQuestion = afterEntre.split(/\b(?:qual|quais|quem)\b/i)[0] || "";

    const terms = normalizeTerms(
      beforeQuestion
        .replace(/[?!.]/g, " ")
        .split(/\s+\be\b\s+/i)
    );

    if (terms.length >= 2) {
      console.log("Þ COMPARISON TERMS EXTRAûDOS ENTRE/E:", {
        query: raw,
        terms
      });

      return terms;
    }
  }

  if (looksLikeMoreQuestion && /\se\s/i.test(raw)) {
    const beforeQuestion = raw.split(/\b(?:qual|quais|quem)\b/i)[0] || "";

    const terms = normalizeTerms(
      beforeQuestion
        .replace(/[?!.]/g, " ")
        .split(/\s+\be\b\s+/i)
    );

    if (terms.length >= 2) {
      console.log("Þ COMPARISON TERMS EXTRAûDOS E:", {
        query: raw,
        terms
      });

      return terms;
    }
  }

  return [];
}

// ======================================================
// CONTEXTUAL AXIS ENGINE ã ETAPA 4.6.34.3
// ======================================================
// Objetivo:
// - Detectar quando o usuûÀrio nûÈo estûÀ fazendo uma nova busca,
//   mas mudando o eixo da comparaûÏûÈo atual.
// Exemplo:
// "a35 ou g84?"
// depois: "e bateria?"
// Resultado: eixo contextual = battery

function detectContextualAxisFromQuery(query = "") {
  const q = normalizeQuery(query || "");

  if (!q) return "";

  if (/\b(e bateria|bateria|autonomia|carga|tomada|dura mais|aguenta mais)\b/i.test(q)) {
    return "battery";
  }

  if (/\b(e camera|e cûÂmera|camera|cûÂmera|foto|fotos|video|vûÙdeo|selfie)\b/i.test(q)) {
    return "camera";
  }

  if (/\b(e desempenho|desempenho|performance|jogo|jogos|trava|fluidez|rapido|rûÀpido|processador|velocidade)\b/i.test(q)) {
    return "performance";
  }

  if (/\b(e tela|tela|display|amoled|oled|lcd|brilho|hz|imagem)\b/i.test(q)) {
    return "screen";
  }

  if (/\b(e armazenamento|armazenamento|memoria|memû°ria|espaco|espaûÏo|128gb|256gb|512gb|1tb)\b/i.test(q)) {
    return "storage";
  }

  if (/\b(e durabilidade|dura anos|vida util|vida û¤til|longevidade|atualizacao|atualizaûÏûÈo|envelhece melhor)\b/i.test(q)) {
    return "longevity";
  }

  if (/\b(e preco|e preûÏo|preco|preûÏo|custo beneficio|custo-benefûÙcio|vale mais|vale a pena|vale pagar|compensa pagar|pagar mais|vale a diferenc|vale a diferen|barato|melhor compra)\b/i.test(q)) {
    return "value";
  }

  return "";
}

function isContextualAxisOnlyQuery(query = "") {
  const q = normalizeQuery(query || "");

  if (!q) return false;

  return (
    q.length <= 45 &&
    !!detectContextualAxisFromQuery(query) &&
    !isExplicitComparisonQuery(query) &&
    !isStrongNewSearchQuery(query)
  );
}

// ======================================================
// ADVANCED CONTEXTUAL INTENT ENGINE ã SUBETAPA 5.2.3
// ======================================================
// Centraliza a interpretaûÏûÈo contextual da comparaûÏûÈo.
// Objetivo:
// - decidir se a pergunta mantûˋm eixo
// - decidir se volta para decisûÈo geral
// - impedir re-heranûÏa indevida de lastPriority
// - orientar reasoning/behavior sem hardcode de frase

function detectComparisonIntentMode({
  query = "",
  resolvedQuery = "",
  sessionContext = {},
  products = [],
  currentPriority = "",
  activePriority = "",
  explicitPriority = ""
} = {}) {
  const normalizedQuery = normalizeQuery(query || "");
  const normalizedResolvedQuery = normalizeQuery(resolvedQuery || "");

  const contextualIntentFromQuery = detectMiaContextualIntent(query);
  const contextualIntentFromResolvedQuery = detectMiaContextualIntent(resolvedQuery);

  const contextualIntent =
    contextualIntentFromQuery?.hasContextualIntent
      ? contextualIntentFromQuery
      : contextualIntentFromResolvedQuery?.hasContextualIntent
        ? contextualIntentFromResolvedQuery
        : {
            hasContextualIntent: false,
            inferredPriority: "",
            contextualWeights: {},
            negativeWeights: {},
            negativeAxes: [],
            hasNegativePriorityIntent: false,
            matchedIntents: [],
            confidence: 0,
            explanation: ""
          };

  const hasComparisonContext =
    hasLockedComparisonContext(sessionContext) ||
    (Array.isArray(products) && products.length >= 2);

  const isExplicitComparison =
    isExplicitComparisonQuery(query) ||
    isExplicitComparisonQuery(resolvedQuery);

  const rawAxisFromQuery =
    detectContextualAxisFromQuery(query) ||
    resolveComparisonFollowUpPriority(query) ||
    detectUserPriority(query) ||
    "";

  const rawAxisFromResolvedQuery =
    detectContextualAxisFromQuery(resolvedQuery) ||
    resolveComparisonFollowUpPriority(resolvedQuery) ||
    detectUserPriority(resolvedQuery) ||
    "";

  const axisFromQuery = sanitizeAxisAgainstNegativeIntent(
    rawAxisFromQuery,
    contextualIntent
  );

  const axisFromResolvedQuery = sanitizeAxisAgainstNegativeIntent(
    rawAxisFromResolvedQuery,
    contextualIntent
  );

  const inferredContextualAxis = sanitizeAxisAgainstNegativeIntent(
    contextualIntent?.inferredPriority || "",
    contextualIntent
  );

  const sanitizedExplicitPriority = sanitizeAxisAgainstNegativeIntent(
    explicitPriority || "",
    contextualIntent
  );

  const directAxis =
    axisFromQuery ||
    axisFromResolvedQuery ||
    sanitizedExplicitPriority ||
    inferredContextualAxis ||
    "";

  const isGeneralPersonalDecision =
    isGeneralPersonalDecisionQuery(query) ||
    isGeneralPersonalDecisionQuery(resolvedQuery);

  const isAxisFollowUp =
    !!directAxis &&
    !isExplicitComparison &&
    !isGeneralPersonalDecision &&
    hasComparisonContext;

  const shouldReturnToOverallReasoning =
    isGeneralPersonalDecision ||
    (
      hasComparisonContext &&
      !directAxis &&
      !isExplicitComparison &&
      /\b(qual|compraria|pegaria|escolheria|iria|ficaria|recomenda|recomendaria|melhor escolha|sua escolha)\b/i.test(
        `${normalizedQuery} ${normalizedResolvedQuery}`
      )
    );

  const inheritedAxis = sanitizeAxisAgainstNegativeIntent(
    sessionContext?.lastContextualAxis ||
      sessionContext?.lastPriority ||
      currentPriority ||
      activePriority ||
      "",
    contextualIntent
  );

  const shouldKeepAxis =
    !!directAxis &&
    !shouldReturnToOverallReasoning;

  const shouldUsePreviousAxisAsSecondaryContext =
    shouldReturnToOverallReasoning && !!inheritedAxis;

  const priority = shouldKeepAxis
    ? directAxis
    : shouldReturnToOverallReasoning
      ? ""
      : (
          directAxis ||
          currentPriority ||
          activePriority ||
          ""
        );

  const finalPriority = sanitizeAxisAgainstNegativeIntent(
    priority,
    contextualIntent
  );

  const reasoningMode = shouldReturnToOverallReasoning
    ? "overall_decision"
    : shouldKeepAxis
      ? "axis_decision"
      : contextualIntent?.hasContextualIntent
        ? contextualIntent?.hasNegativePriorityIntent
          ? "negative_contextual_preference_decision"
          : "contextual_human_intent_decision"
        : isExplicitComparison
          ? "overall_decision"
          : "contextual_decision";

  const intentType = shouldReturnToOverallReasoning
    ? "general_personal_decision"
    : shouldKeepAxis
      ? "axis_followup"
      : contextualIntent?.hasContextualIntent
        ? contextualIntent?.hasNegativePriorityIntent
          ? "negative_human_context"
          : "implicit_human_context"
        : isExplicitComparison
          ? "explicit_comparison"
          : "comparison_context";

  const contextualWeights = {
    overall: shouldReturnToOverallReasoning ? 1 : 0.7,
    axis: shouldKeepAxis ? 1 : 0,
    previousAxis: shouldUsePreviousAxisAsSecondaryContext ? 0.35 : 0,
    ...(contextualIntent?.contextualWeights || {})
  };

  return {
    version: "5.2.5-negative-priority",
    intentType,
    reasoningMode,
    priority: finalPriority,
    directAxis,
    inheritedAxis,
    shouldKeepAxis,
    shouldReturnToOverallReasoning,
    shouldUsePreviousAxisAsSecondaryContext,
    shouldStayInComparisonContext: hasComparisonContext || isExplicitComparison,
    isGeneralPersonalDecision,
    isAxisFollowUp,
    isExplicitComparison,
    contextualWeights,
    negativeWeights: contextualIntent?.negativeWeights || {},
    negativeAxes: contextualIntent?.negativeAxes || [],
    hasNegativePriorityIntent: !!contextualIntent?.hasNegativePriorityIntent,
    contextualIntent,
    conversationalIntention: shouldReturnToOverallReasoning
      ? "personal_overall_recommendation"
      : shouldKeepAxis
        ? "axis_specific_explanation"
        : contextualIntent?.hasNegativePriorityIntent
          ? "negative_preference_recommendation"
          : contextualIntent?.hasContextualIntent
            ? "human_contextual_recommendation"
            : "comparison_decision"
  };
}

function resolveContextualComparisonAxis({
  query = "",
  resolvedQuery = "",
  sessionContext = {},
  products = [],
  currentPriority = "",
  activePriority = ""
} = {}) {
  const comparisonIntentMode = detectComparisonIntentMode({
    query,
    resolvedQuery,
    sessionContext,
    products,
    currentPriority,
    activePriority
  });

  return comparisonIntentMode.priority || "";
}

