function getNegativePriorityAxesFromContextualIntent(contextualIntent = null) {
  if (!contextualIntent?.negativeWeights) return [];

  return Object.entries(contextualIntent.negativeWeights)
    .filter(([, weight]) => Number(weight) < 1)
    .map(([axis]) => axis);
}

function hasNegativePriorityIntentForAxis(contextualIntent = null, axis = "") {
  if (!contextualIntent || !axis) return false;

  const negativeAxes = getNegativePriorityAxesFromContextualIntent(contextualIntent);

  return negativeAxes.includes(axis);
}

function hasAnyNegativePriorityIntent(contextualIntent = null) {
  return getNegativePriorityAxesFromContextualIntent(contextualIntent).length > 0;
}

function sanitizeAxisAgainstNegativeIntent(axis = "", contextualIntent = null) {
  if (!axis) return "";

  if (hasNegativePriorityIntentForAxis(contextualIntent, axis)) {
    return "";
  }

  return axis;
}

// ======================================================
// CONTEXTUAL EXPLANATION SUPPRESSION ã ETAPA 4.20
// ======================================================
// Remove da explicaûÏûÈo os eixos que o usuûÀrio disse nûÈo valorizar.
// Exemplo: "nûÈo ligo pra cûÂmera" => cûÂmera nûÈo deve virar destaque,
// tradeoff principal, base objetiva principal ou motivo central.

const MIA_SUPPRESSION_AXIS_LABELS = {
  performance: "desempenho",
  camera: "cûÂmera",
  battery: "bateria",
  screen: "tela",
  longevity: "longevidade",
  value: "custo-benefûÙcio",
  storage: "armazenamento"
};

function getSuppressedAxesFromReasoningProfiles(profiles = []) {
  if (!Array.isArray(profiles)) return [];

  const axes = new Set();

  for (const profile of profiles) {
    const profileSuppressedAxes = Array.isArray(profile?.suppressedAxes)
      ? profile.suppressedAxes
      : [];

    const contextualNegativeAxes = Array.isArray(profile?.contextualIntent?.negativeAxes)
      ? profile.contextualIntent.negativeAxes
      : [];

    for (const axis of [...profileSuppressedAxes, ...contextualNegativeAxes]) {
      if (axis) axes.add(axis);
    }
  }

  return Array.from(axes);
}

function filterSuppressedExplanationAxes(items = [], suppressedAxes = []) {
  if (!Array.isArray(items)) return [];

  const blocked = new Set(suppressedAxes || []);

  return items.filter((item) => {
    const key = item?.key || "";
    return key ? !blocked.has(key) : true;
  });
}

function filterSuppressedReasonTags(reasonTags = [], suppressedAxes = []) {
  if (!Array.isArray(reasonTags)) return [];

  const blocked = new Set(suppressedAxes || []);

  return reasonTags.filter((tag) => {
    if (!tag) return false;

    if (blocked.has("camera") && /camera|cûÂmera/i.test(tag)) return false;
    if (blocked.has("performance") && /performance|desempenho/i.test(tag)) return false;
    if (blocked.has("battery") && /battery|bateria/i.test(tag)) return false;
    if (blocked.has("screen") && /screen|tela/i.test(tag)) return false;
    if (blocked.has("longevity") && /longevity|longevidade/i.test(tag)) return false;
    if (blocked.has("value") && /value|custo|benef/i.test(tag)) return false;

    return true;
  });
}

function buildExplanationSuppressionGovernance(suppressedAxes = []) {
  const axes = Array.isArray(suppressedAxes)
    ? suppressedAxes.filter(Boolean)
    : [];

  const labels = axes.map((axis) => MIA_SUPPRESSION_AXIS_LABELS[axis] || axis);

  return {
    active: axes.length > 0,
    version: "4.20",
    suppressedAxes: axes,
    suppressedLabels: labels,
    rule:
      axes.length > 0
        ? `O usuûÀrio indicou baixa importûÂncia para: ${labels.join(", ")}. Esses eixos nûÈo devem aparecer como motivo central, tradeoff principal ou destaque da base objetiva.`
        : "",
    allowedBehavior: {
      canMentionSuppressedAxisBriefly: true,
      canUseSuppressedAxisAsSecondaryObservation: true
    },
    forbiddenBehavior: {
      mustNotUseSuppressedAxisAsMainReason: true,
      mustNotOpenWithSuppressedAxis: true,
      mustNotCloseWithSuppressedAxis: true,
      mustNotPresentSuppressedAxisAsMainTradeoff: true,
      mustNotPutSuppressedAxisFirstInObjectiveBase: true
    }
  };
}

