function getOfficialSpecs(product = {}) {
  const title = normalizeQuery(product.product_name || product.title || "");

  if (!title) return null;

  const found = OFFICIAL_PRODUCT_SPECS.find((item) =>
    item.aliases.some((regex) => regex.test(title))
  );

  if (!found) return null;

  return {
    officialName: found.name,
    specs: found.specs
  };
}

function getOfficialPriorityValue(officialSpecs = null, priority = "", product = {}) {
  if (!officialSpecs?.specs) return null;

  const specs = officialSpecs.specs;
  const price = parsePrice(product.price);

  if (priority === "battery") {
    return typeof specs.batteryMah === "number" ? specs.batteryMah : null;
  }

  if (priority === "storage") {
    return typeof specs.storageGb === "number" ? specs.storageGb : null;
  }

  if (priority === "performance") {
    return typeof specs.performanceScore === "number" ? specs.performanceScore : null;
  }

  if (priority === "camera") {
    return typeof specs.cameraScore === "number" ? specs.cameraScore : null;
  }

  if (priority === "comfort") {
    return typeof specs.comfortScore === "number" ? specs.comfortScore : null;
  }

  if (priority === "efficiency") {
    return typeof specs.efficiencyScore === "number" ? specs.efficiencyScore : null;
  }

  if (priority === "value") {
    return Number.isNaN(price) ? null : Math.max(0, 1000000 - price);
  }

  return null;
}

function formatOfficialPriorityValue(priority = "", value = null) {
  if (value === null || value === undefined) return "";

  if (priority === "battery") return `${value}mAh`;
  if (priority === "storage") return `${value}GB`;
  if (priority === "performance") return `score ${value} de desempenho`;
  if (priority === "camera") return `score ${value} de cûÂmera`;
  if (priority === "comfort") return `score ${value} de conforto`;
  if (priority === "efficiency") return `score ${value} de eficiûˆncia`;
  if (priority === "value") return "melhor preûÏo/custo";

  return String(value);
}

function decideByOfficialSpecs(products = [], priority = "", query = "", sessionContext = {}) {
  if (!priority || !Array.isArray(products) || products.length < 2) {
    return null;
  }

  const priorityLabel = getPriorityLabel(priority);

  const enriched = products.map((product) => {
    const official = getOfficialSpecs(product);
    const officialValue = getOfficialPriorityValue(official, priority, product);

    return {
      ...product,
      official,
      officialValue,
      title: getStrongDisplayTitle(official?.officialName || product.product_name)
    };
  });

  const comparable = enriched.filter((product) => product.officialValue !== null);

  if (comparable.length < 2) {
    return {
      winner: enriched[0],
      alternative: enriched[1] || null,
      priority,
      cardProduct: enriched[0],
      productsUsed: enriched,
      reply:
        `Eu nûÈo vou cravar uma escolha por ${priorityLabel} sem ficha tûˋcnica confiûÀvel dos produtos.\n\n` +
        `Pra nûÈo te induzir ao erro, preciso comparar as especificaûÏûçes oficiais desses modelos antes de dizer qual vence.`
    };
  }

  comparable.sort((a, b) => b.officialValue - a.officialValue);

  const winner = comparable[0];
  const alternative = comparable[1] || null;

  const winnerValue = formatOfficialPriorityValue(priority, winner.officialValue);
  const alternativeValue = alternative
    ? formatOfficialPriorityValue(priority, alternative.officialValue)
    : "";

  let reply = `Pela ficha tûˋcnica confiûÀvel, eu iria no ${winner.title}.`;

  reply += `\n\nSua prioridade ûˋ ${priorityLabel}, entûÈo essa prioridade manda na decisûÈo.`;

  reply += `\n\nComparando pela especificaûÏûÈo oficial:`;
  reply += `\n- ${winner.title}: ${winnerValue}.`;

  if (alternative) {
    reply += `\n- ${alternative.title}: ${alternativeValue}.`;
  }

  reply += `\n\nResumo: como sua prioridade ûˋ ${priorityLabel}, vai no ${winner.title}.`;

  return {
    winner,
    alternative,
    priority,
    cardProduct: winner,
    productsUsed: comparable,
    reply: reply.replace(/\*\*/g, "").trim()
  };
}
