const getGrammar = (title = "") => {
  const t = normalizeQuery(title);

  const isFemale =
    /tv|televisao|televisûÈo|smart\s*tv|cadeira|mesa|geladeira|maquina|mûÀquina|lavadora/.test(t);

  const isAudio =
    /fone|fones|headphone|earbud|audio|ûÀudio/.test(t);

  if (isFemale) {
    return {
      esse: "essa",
      nesse: "nessa",
      nele: "nela",
      artigo: "a",
      porEsse: "por essa"
    };
  }

  if (isAudio) {
    return {
      esse: "esse",
      nesse: "nesse",
      nele: "nele",
      artigo: "o",
      porEsse: "por esse"
    };
  }

  return {
    esse: "esse",
    nesse: "nesse",
    nele: "nele",
    artigo: "o",
    porEsse: "por esse"
  };
};

